import json, re
from collections import Counter

d = json.load(open('/tmp/low_conf_confirms.json'))

# Categorize by language pattern
buckets = Counter()
samples = {}
for item in d:
    rat = item['rationale'].lower()
    if 'no principle' in rat or 'no specific principle' in rat or 'principle speaks' in rat:
        bucket = 'no_principle_speaks'
    elif 'no principled' in rat or 'no principled basis' in rat:
        bucket = 'no_principled_basis'
    elif 'reasonable' in rat and ('alternative' in rat or 'either' in rat or 'both' in rat):
        bucket = 'either_works'
    elif 'judgment call' in rat or 'judgement call' in rat or 'taste' in rat:
        bucket = 'taste_or_judgment'
    elif 'evidence' in rat and ('insufficient' in rat or 'limited' in rat or "don't have" in rat):
        bucket = 'insufficient_evidence'
    elif 'tie' in rat or 'wash' in rat or 'either' in rat:
        bucket = 'tie_or_wash'
    elif 'speculative' in rat:
        bucket = 'speculative_either_way'
    else:
        bucket = 'other'
    buckets[bucket] += 1
    if bucket not in samples:
        samples[bucket] = []
    if len(samples[bucket]) < 3:
        samples[bucket].append(item)

print('Buckets:')
for b, n in buckets.most_common():
    print(f'  {n:>3}  {b}')

print()
print('Samples from \"other\" bucket:')
for item in samples.get('other', []):
    print('  -', item['rationale'][:200])
EOF
